{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "description": "ENERGY STAR Score by Primary Property Type (mean bars with median ticks)",
  "title": "ENERGY STAR Score by Primary Property Type",
  "data": { "name": "edf" },
  "width": 600,
  "height": 400,
  "layer": [
    {
      "transform": [
        {
          "aggregate": [
            { "op": "mean", "field": "ENERGY STAR Score", "as": "mean_score" }
          ],
          "groupby": ["Primary Property Type"]
        }
      ],
      "mark": "bar",
      "encoding": {
        "y": {
          "field": "Primary Property Type",
          "type": "nominal",
          "title": "Primary Property Type"
        },
        "x": {
          "field": "mean_score",
          "type": "quantitative",
          "scale": { "domain": [0, 100] },
          "title": "Mean ENERGY STAR Score"
        },
        "tooltip": [
          {
            "field": "Primary Property Type",
            "type": "nominal",
            "title": "Primary Property Type"
          },
          {
            "field": "mean_score",
            "type": "quantitative",
            "title": "Mean ENERGY STAR Score",
            "format": ".2f"
          }
        ]
      }
    },
    {
      "transform": [
        {
          "aggregate": [
            { "op": "median", "field": "ENERGY STAR Score", "as": "median_score" }
          ],
          "groupby": ["Primary Property Type"]
        }
      ],
      "mark": {
        "type": "tick",
        "color": "red",
        "thickness": 2
      },
      "encoding": {
        "y": {
          "field": "Primary Property Type",
          "type": "nominal"
        },
        "x": {
          "field": "median_score",
          "type": "quantitative",
          "scale": { "domain": [0, 100] },
          "title": "Median ENERGY STAR Score"
        },
        "tooltip": [
          {
            "field": "Primary Property Type",
            "type": "nominal",
            "title": "Primary Property Type"
          },
          {
            "field": "median_score",
            "type": "quantitative",
            "title": "Median ENERGY STAR Score",
            "format": ".2f"
          }
        ]
      }
    }
  ]
}
